/* 朋克小鼠的上班日-小羊莓 */
/* 禁止二传贩卖 */
/* 感谢名单：
改图建议：易碎蝶（谢谢我蝶的代码和改图建议）
代码：部分来自lc美化教程贴的老师们（感谢老师们）
图标等装饰等均来自小红书：@小红薯693587B3（朋克小鼠）@总是忧郁体质老师（导航框图标）@牛奶熊（输入框图标和编辑-消息操作图标）@0011556677（头图文字）@不管发生什么都呆胶布（头图文字装饰）@牛逼哄哄咩小耶（头图装饰）@吐司面包鱼（头图装饰）@小狗布丁（头图-底图小鼠图装饰）感谢各位分享素材的老师*/

/* =========================================
   1. 字体与全局背景
   ========================================= */

/* --- 自定义字体 --- */
@import url("https://fontsapi.zeoseven.com/701/main/result.css"); /* 🐭 可以在这里替换字体链接 */

body, button, input, textarea, select {
  font-family: "NaikaiFont", sans-serif !important;
  font-weight: normal !important;
}

/* --- 界面全局背景 --- */
.drawer-content {
  background: 
    linear-gradient(rgba(250, 248, 255, 0), rgba(250, 248, 255, 0)),
    url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center / cover no-repeat fixed !important; /* 🐭 在这里替换全局背景图片链接 */
}


/* =========================================
   2. 变量设置 (颜色与尺寸)
   ========================================= */
:root {
    /* --- 主题颜色 --- */
    --cute-background: #f5f5f5;          /* 🐭 背景淡灰色 */
    --cute-grid-line: rgba(0, 0, 0, 0.08); /* 🐭 网格线颜色 */
    --cute-border-color: #888888;        /* 🐭 边框深灰色 */
    --cute-shadow-color: rgba(0, 0, 0, 0.15); /* 🐭 阴影颜色 */

    /* --- 导航栏尺寸 --- */
    --panel-bar-height: 34px;      /* 🐭 导航栏高度 */
    --panel-bar-top-offset: 1px;   /* 🐭 距离顶部的距离 */
    --panel-bar-side-inset: 0px;   /* 🐭 左右缩进距离 */

    /* --- 导航栏图标 --- */
    --icon-normal-url: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 🐭 默认图标链接 */
    --icon-hover-url: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');  /* 🐭 悬停图标链接 */
    --icon-size: 28px;             /* 🐭 图标大小 */
    --icon-spacing: 4px;           /* 🐭 图标间距 */
    --icon-vertical-offset: 4px;   /* 🐭 图标垂直微调 */
    --icon-hover-effect: scale(1.1);
}


/* =========================================
   3. 顶部导航栏 (Top Bar)
   ========================================= */
#top-bar {
    position: fixed !important;
    top: var(--panel-bar-top-offset) !important;
    left: var(--panel-bar-side-inset) !important;
    right: var(--panel-bar-side-inset) !important;
    height: var(--panel-bar-height) !important;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 !important;
    z-index: 1000;
    background: transparent !important;
    border: 1px solid var(--cute-border-color);
    border-radius: 6px;
    box-shadow: 1px 1px 0px var(--cute-shadow-color) !important;
    transition: all 0.3s ease;
}

/* --- 背景虚线网格 --- */
#top-bar::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    z-index: -1;
    background-color: var(--cute-background);
    background-image:
        linear-gradient(to right, var(--cute-grid-line) 50%, transparent 50%),
        linear-gradient(to bottom, var(--cute-grid-line) 50%, transparent 50%);
    background-size: 14px 14px; /* 🐭 这里修改网格的大小 */
    border-radius: 5px;
}

/* --- 底部装饰波浪 --- */
#top-bar::after {
    content: '';
    position: absolute;
    width: 100%;
    height: 6px; /* 🐭 波浪区域高度 */
    left: 0;
    bottom: -4px; /* 🐭 调整波浪上下位置 */
    z-index: -1;
    background-image: linear-gradient(to right, var(--cute-border-color) 50%, transparent 50%);
    background-size: 4px 1px;
    background-repeat: repeat-x;
    background-position: center;
    mask-image: repeating-radial-gradient(circle at center, black 0, black 3px, transparent 3px);
    mask-size: 14px 7px;
    -webkit-mask-image: repeating-radial-gradient(circle at center, black 0, black 3px, transparent 3px);
    -webkit-mask-size: 14px 7px;
}

/* --- 导航栏图标样式 --- */
.drawer-icon.fa-fw {
    background: var(--icon-normal-url) center / contain no-repeat !important;
    width: var(--icon-size) !important;
    height: var(--icon-size) !important;
    margin: 0 var(--icon-spacing) !important;
    transform: translateY(var(--icon-vertical-offset));
    transition: transform 0.2s ease;
}
.drawer-icon.fa-fw::before {
    display: none !important;
}
.drawer-icon.fa-fw:hover,
.drawer-icon.fa-fw.openIcon {
    background-image: var(--icon-hover-url) !important;
    transform: var(--icon-hover-effect) translateY(var(--icon-vertical-offset));
}


/* =========================================
   4. 顶部装饰物 (垂落的鼠鼠)
   ========================================= */
#top-bar {
    position: relative;
}

/* 重新声明以防覆盖，保持网格背景 */
#top-bar::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    z-index: -1;
    background-color: var(--cute-background);
    background-image: linear-gradient(to right, var(--cute-grid-line) 50%, transparent 50%),
        linear-gradient(to bottom, var(--cute-grid-line) 50%, transparent 50%);
    background-size: 14px 14px;
    border-radius: 5px;
}

/* --- 垂下来的可爱鼠鼠 --- */
#top-bar::after {
    content: '';
    position: absolute;

    /* 🐭 核心位置调整 */
    top: calc(100% - 4px); /* 🐭 上下位置：数值越大挂得越高 */
    left: 0%;              /* 🐭 左右位置：0%最左，50%居中，100%最右 */
    transform: translateX(-50%); /* 保持中心对准 */

    z-index: 10;

    /* 🐭 尺寸与图片 */
    width: 65px;  /* 🐭 装饰物宽度 */
    height: 76px; /* 🐭 装饰物高度 */
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 🐭 装饰物图片链接 */
    background-size: contain;
    background-repeat: no-repeat;

    /* 动画 */
    animation: swinging-decoration 5s ease-in-out infinite;
    transform-origin: top center;
}

/* 摇摆动画 */
@keyframes swinging-decoration {
    0%   { transform: rotate(3deg); }
    50%  { transform: rotate(-3deg); }
    100% { transform: rotate(3deg); }
}

/* 调整聊天区域顶部间距 */
#chat {
    padding-top: calc(var(--panel-bar-height) + var(--panel-bar-top-offset) + 20px) !important;
}


/* =========================================
   5. 聊天气泡主界面 (三段式)
   ========================================= */
/* @nini老师（二改版感谢老师） */
.mes:not(#chat-end) {
    /* 🐭 --- 画布宽度控制 --- */
    --middle-max-width: 500px; /* 🐭 气泡最大宽度 */

    /* 🐭 --- 文字内边距控制 --- */
    --text-padding-top: 0px;      /* 🐭 上内边距 */
    --text-padding-bottom: 40px;  /* 🐭 下内边距 */
    --text-padding-left: 15px;    /* 🐭 左内边距 */
    --text-padding-right: 15px;   /* 🐭 右内边距 */

    /* 🐭 --- 信息栏位置预设 (下面有单独控制区，这里可忽略) --- */
    --id-display-top: -90px;
    --id-display-left: 15px;
    --token-counter-top: -80px;
    --token-counter-left: 15px;
    --timer-top: -50px;
    --timer-left: 15px;

    /* 基础设定 */
    position: relative !important;
    width: 96% !important;
    max-width: var(--middle-max-width) !important;
    z-index: 2 !important;
    border: none !important;
    box-shadow: none !important;
    margin-left: auto !important;
    margin-right: auto !important;
    margin-top: 260px !important;    /* 🐭 气泡距离上方的间距 (头像空间) */
    margin-bottom: 70px !important;  /* 🐭 气泡距离下方的间距 */
    padding: var(--text-padding-top) var(--text-padding-right) var(--text-padding-bottom) var(--text-padding-left) !important;

    /* 🐭 背景图设置 */
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") !important; /* 🐭 中间部分背景图链接 */
    background-repeat: repeat-y !important;
    background-position: top center !important;
    background-size: 100% auto !important;
    background-color: white !important;
}

/* --- 正文与段落间距 --- */
.mes_text, .mes_reasoning {
    padding: 0 !important;
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    width: 100%;
    max-width: 100%;
    overflow-wrap: anywhere;
    box-sizing: border-box;
}

/* 清除默认边距 */
.mes_text p, .mes_reasoning p {
    margin: 0 !important;
    padding: 0 !important;
}

/* 🐭 段落间距控制 */
.mes_text p + p, .mes_reasoning p + p {
    margin-top: 10px !important; /* 🐭 修改这里的数值调整段落之间的距离 */
}

/* 清除 SillyTavern 默认 padding */
.mes_block {
    padding: 0 !important;
}

/* @lambkinling老师感谢 */
.mes_text {
  text-align: justify; /* 🐭 left=左对齐, center=居中, justify=两端对齐 */
}
/* 名字和时间戳移位修复@_nak.a.ri老师*/
.mes_block {
  transform: none !important;
}
/* 三元素修复移位 @ camellia1007老师*/
.mesAvatarWrapper {
  transform: none !important;
}

/* =========================================
   6. 气泡贴纸 (上层与下层)
   ========================================= */

/* --- 上层贴纸 (顶部装饰) --- */
.mes:not(#chat-end)::before {
    /* 🐭 --- 尺寸与位置微调 --- */
    --top-width: 403px;    /* 🐭 图片宽度 */
    --top-height: 303px;   /* 🐭 图片高度 */
    --top-h-offset: -2px;  /* 🐭 水平微调 (正数向右，负数向左) */
    --top-v-offset: 20px;  /* 🐭 垂直微调 (正数向下，负数向上) */

    content: '';
    position: absolute;
    width: var(--top-width);
    height: var(--top-height);
    top: 0;
    left: 50%;
    transform: translateY(-100%) translateX(-50%) 
               translateX(var(--top-h-offset)) 
               translateY(var(--top-v-offset));
    pointer-events: none;
    z-index: 2;
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII="); /* 🐭 上层装饰图片链接 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
}

/* --- 下层贴纸 (底部装饰) --- */
.mes:not(#chat-end)::after {
    /* 🐭 --- 尺寸与位置微调 --- */
    --bottom-width: 373px;  /* 🐭 图片宽度 */
    --bottom-height: 50px;  /* 🐭 图片高度 */
    --bottom-h-offset: 0px; /* 🐭 水平微调 */
    --bottom-v-offset: -10px; /* 🐭 垂直微调 */

    content: '';
    position: absolute;
    width: var(--bottom-width);
    height: var(--bottom-height);
    top: 100%;
    left: 50%;
    transform: translateX(-50%) 
               translateX(var(--bottom-h-offset)) 
               translateY(var(--bottom-v-offset));
    pointer-events: none;
    z-index: -1;
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII="); /* 🐭 下层装饰图片链接 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
}

/* 底部结束符样式 */
#chat-end {
    padding: 20px !important;
    margin: 40px 0 !important;
    background: transparent !important;
}


/* =========================================
   7. 头像美化 
   ========================================= */
.mes .avatar {
    /* 🐭 --- 尺寸位置 --- */
    --avatar-width: 110px;
    --avatar-height: 150px;
    --avatar-top: -220px;
    --avatar-left: 245px;

    /* 🐭 ---在这里改颜色 --- */

    /* 1. 图片去色程度 (0% = 原色/暖色; 100% = 黑白/纯灰) */
    --img-grayscale: 100%; 

    /* 2. 滤镜层颜色 */
    --filter-color: #778899; 

    /* 3. 滤镜层浓度 (0 = 透明; 1 = 纯实色) */
    /* 觉得太黑就调小这个数字，0.1-0.3 比较合适 */
    --filter-opacity: 0.2; 

    /* --- 基础样式 --- */
    position: absolute !important;
    width: var(--avatar-width) !important;
    height: var(--avatar-height) !important;
    top: var(--avatar-top) !important;
    left: var(--avatar-left) !important;
    z-index: 1 !important;

    border-radius: 0px !important;
    overflow: hidden !important;   
    box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.25) !important;
}

/* 头像图片本体 */
.mes .avatar img {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover !important;
    border: none !important; 
    border-radius: 0px !important;
    box-shadow: none !important;

    /* 🐭 关键：应用去色效果！让暖色变灰 */
    filter: grayscale(var(--img-grayscale)) !important;
}

/* 滤镜遮罩层 */
.mes .avatar::after {
    content: '' !important;
    position: absolute !important;
    top: 0; left: 0;
    width: 100%; 
    height: 100%;

    /* 🐭 应用你设置的颜色 */
    background-color: var(--filter-color) !important;

    /* 🐭 应用你设置的透明度 */
    opacity: var(--filter-opacity) !important;

    pointer-events: none; 
    z-index: 2; 
    /* 混合模式：叠加 (可选，如果你想要更高级的融合感可以把下面这行前面的注释去掉) */
    /* mix-blend-mode: overlay; */
}

/* =========================================
   8. 角色名称 (Name)
   ========================================= */
.mes .ch_name {
    /* 🐭 --- 名字控制面板 --- */
    --name-font-size: 16px;     /* 🐭 字体大小 */
    --name-color: #4a4a4a;      /* 🐭 字体颜色 */
    --name-top: -205px;         /* 🐭 上下位置 */
    --name-left: 20px;          /* 🐭 左右位置 */

    position: absolute !important; 
    top: var(--name-top) !important;
    left: var(--name-left) !important;
    font-size: var(--name-font-size) !important;
    color: var(--name-color) !important;
    font-weight: bolder !important;
    white-space: nowrap; 
    z-index: 3 !important;
}

.mes .ch_name .name_text {
    color: var(--name-color) !important;
}


/* =========================================
   9. 时间戳 (Timestamp)
   ========================================= */
.timestamp {
    /* 🐭 --- 时间戳控制面板 --- */
    --timestamp-font-size: 9px; /* 🐭 字体大小 */
    --timestamp-color: #b0b0b0; /* 🐭 字体颜色 */
    --timestamp-top: 120px;     /* 🐭 上下位置 */
    --timestamp-left: 230px;    /* 🐭 左右位置 */

    position: absolute !important; 
    top: var(--timestamp-top) !important;
    left: var(--timestamp-left) !important;
    font-size: var(--timestamp-font-size) !important;
    color: var(--timestamp-color) !important;
    font-weight: 400 !important;
    white-space: nowrap; 
    opacity: 1 !important; 
    z-index: 3 !important;
}


/* =========================================
   10. 编辑与消息操作图标 (Buttons) - 灰白极简版
   ========================================= */
/* 隐藏原图标 */
.mes_edit > i,
.extraMesButtonsHint > i,
.mes_edit::before,
.extraMesButtonsHint::before {
    display: none !important;
    content: '' !important;
}

/* 铅笔图标 (编辑) */
.mes_edit {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important; 
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    width: 28px !important; 
    height: 28px !important; 
    background-color: transparent !important;
    transition: transform 0.2s ease !important;
    cursor: pointer !important;
    box-shadow: none !important;

    /* 🐭 核心修改：去色 + 灰白阴影 */
    /* grayscale(100%): 把粉色变成灰色 */
    /* drop-shadow: 加一个白色的描边/投影，让它在复杂背景上也能看清 */
    filter: grayscale(100%) drop-shadow(1px 1px 0px rgba(255, 255, 255, 0.8));

    /* 如果觉得太黑，可以加 brightness(1.2) 提亮，或者 opacity(0.6) 变淡 */
    opacity: 0.7; /* 默认稍微淡一点，不抢眼 */
}

/* 三点图标 (更多操作) */
.extraMesButtonsHint {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important; 
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    width: 32px !important; 
    height: 32px !important; 
    background-color: transparent !important;
    transition: transform 0.2s ease !important;
    cursor: pointer !important;
    box-shadow: none !important;

    /* 🐭 核心修改：同上，去色 + 灰白阴影 */
    filter: grayscale(100%) drop-shadow(1px 1px 0px rgba(255, 255, 255, 0.8));
    opacity: 0.7;
}

/* 悬停效果 */
.mes_edit:hover,
.extraMesButtonsHint:hover {
    transform: scale(1.15) !important;
    opacity: 1; /* 鼠标放上去时变清晰 */
    /* 悬停时加一点点深色阴影，增加立体感 */
    filter: grayscale(100%) drop-shadow(0 2px 3px rgba(0, 0, 0, 0.15));
}

/* 按钮组位置 @Camellia老师 */
.mes_buttons {
    /* 🐭 --- 按钮组位置控制 --- */
    --buttons-top: 180px;     /* 🐭 上下位置 */
    --buttons-right: -200px;  /* 🐭 左右位置 */

    position: absolute !important;
    top: var(--buttons-top) !important;
    right: var(--buttons-right) !important;
    left: auto !important;
    z-index: 10 !important;
}

/* @易碎蝶老师的编辑移动位置与去阴影 */
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: #5e5e5e !important;
opacity: 0.4 !important; 
}

.mes_edit_buttons {
    /* 🐭 1. 开启定位功能 (必须要有这句) */
    position: relative !important;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: none; /*移除阴影*/
    transition: 0.3s ease-in-out;

    /* ⭕编辑菜单位置核心调整⭕ */
    position: relative;
    top: 200px;  /* 负数上移 | 正数下移  */
    right: 10px;   /* 负数右移 | 正数左移  */

  transform: rotate(0deg); /* 旋转 */
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}


/* =========================================
   11. 信息栏 (楼层/字符数/计时器)
   ========================================= */
.mes .mes_timer,
.mes .mesIDDisplay,
.mes .tokenCounterDisplay {
    position: absolute !important;
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.7);
    font-weight: 600;
    z-index: 5 !important;
}

/* 🐭 楼层显示位置 */
.mes .mesIDDisplay {
    top: -140px !important;  /* 🐭 上下位置 */
    left: 180px !important;  /* 🐭 左右位置 */
}

/* 🐭 字符数显示位置 */
.mes .tokenCounterDisplay {
    top: -128px !important;  /* 🐭 上下位置 */
    left: 180px !important;  /* 🐭 左右位置 */
}

/* 🐭 计时器显示位置 */
.mes .mes_timer {
    top: -115px !important;  /* 🐭 上下位置 */
