.mes_text strong::before, .mes_text strong::after { content: none !important; }

/* 代码块 (code) */
.mes_text code {
    font-family: 'SF Mono', 'Courier New', Courier, monospace !important;
    background-color: var(--mouse-emboss-bg) !important; 
    color: var(--mouse-text) !important;
