/* 🐭 19.1 头部设计 (纯文字链接感) */
.mes_reasoning_header {
    cursor: pointer; 
    position: relative; 
    user-select: none;

    /* 布局：紧凑 */
    margin: 10px 0 2px 8px !important; 
    padding: 2px 0px !important; /* 去掉胶囊的内边距 */
