/* 展开状态 */
details[open] > .mes_reasoning_header {
    opacity: 1 !important; /* 展开后完全不透明 */
}

details[open] > .mes_reasoning_header::before {
    color: #444444 !important; /* 展开后文字变深 */
    border-bottom-color: #DDDDDD !important; /* 出现一条淡淡的下划线，表示“标题” */
}

/* 隐藏原生元素 */
.mes_reasoning_header_title, .mes_reasoning_arrow { display: none !important; }


/* 🐭 19.2 内容区域 (波点卡片 - 保持不变，配合文字很好看) */
.mes_reasoning {
    position: relative; 
    box-sizing: border-box;

    /* 位置 */
    margin: 2px auto 15px auto !important; 
    width: 98% !important; 
    max-width: 100% !important; 
    padding: 20px 25px !important; 

    /* 样式：纯白底 + 极淡波点 */
    background-color: #FFFFFF !important;
    background-image: radial-gradient(#F2F2F2 1.5px, transparent 1.5px) !important;
    background-size: 12px 12px !important; 

    /* 边框 */
    border: 1px dashed #DDDDDD !important; 
    border-radius: 12px !important; 

    /* 字体 */
    color: #666666 !important; 
    font-family: inherit !important;
    font-size: 13.5px !important; 
    line-height: 1.7 !important;
    font-style: normal !important;

    display: block !important;
}

/* 🐭 19.3 装饰：顶部中间的 "胶带" (Washi Tape) */
.mes_reasoning::before {
    content: '';
    position: absolute;
    top: -6px; /* 贴在边框上 */
    left: 50%;
    transform: translateX(-50%);

    width: 30px;
    height: 8px;

    background-color: #EEEEEE;
    border-radius: 2px;
    opacity: 0.8;
}

/* 确保文字换行 */
.mes_text, .mes_reasoning { overflow-wrap: anywhere; }


/* =========================================
   20. 加载动画与杂项 (Spinner & Extras)
   ========================================= */

/* 加载动画 */
#load-spinner {
    position: fixed !important; 
    top: 50% !important; 
    left: 50% !important;
    margin: 0 !important;
    width: 150px !important;  /* 🐭 动画宽度 */
    height: 150px !important; /* 🐭 动画高度 */
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center / contain no-repeat !important; /* 🐭 加载图片链接 */
    animation: cuteMouseBounce 4s ease-in-out infinite !important;
}

#load-spinner::before { 
    display: none !important; 
}

@keyframes cuteMouseBounce {
    0%, 100% {
        transform: translate(-50%, -50%) rotate(-1deg) scale(1);
        filter: drop-shadow(0 10px 15px rgba(100, 100, 100, 0.1));
    }
    50% {
        transform: translate(-50%, -52%) rotate(1deg) scale(1.05);
        filter: drop-shadow(0 18px 25px rgba(100, 100, 100, 0.15));
    }
}

#spinner-overlay {
    background-color: rgba(245, 245, 245, 0.7) !important;
    backdrop-filter: blur(5px) !important;
    -webkit-backdrop-filter: blur(5px) !important;
}

/* 聊天滑动页数图标 */
.mes .swipe_buttons_holder {
    display: none !important;
}
.mes .swipe_left,
.mes .swipe_right {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    font-size: 0 !important;
    width: 28px !important;  /* 🐭 按钮大小 */
    height: 28px !important;
    position: absolute !important;
    z-index: 20 !important;
    opacity: 1 !important;
    bottom: 10px !important; /* 🐭 底部距离 */
}
.mes .swipe_left::before,
.mes .swipe_right::before {
    content: '' !important;
    position: absolute;
    top: 0; left: 0; width: 100%; height: 100%;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    transition: transform 0.2s ease;
}

/* 🐭 左右翻页箭头图片 */
.mes .swipe_left::before {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important;
}
.mes .swipe_right::before {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important;
}

.mes .swipe_left { left: 40px !important; }  /* 🐭 左箭头位置 */
.mes .swipe_right { right: 40px !important; } /* 🐭 右箭头位置 */

/* 页数计数器 */
.mes .swipes-counter,
.mes .swipe_counter {
    position: absolute !important;
    bottom: 8px !important;   /* 🐭 计数器底部距离 */
    right: 175px !important;  /* 🐭 计数器右侧距离 */
    font-size: 12px !important;
    z-index: 21 !important;
    font-weight: 600 !important;
    opacity: 0.8 !important;
    width: auto !important;
    color: #000000 !important; /* 🐭 字体颜色 */
    text-shadow: none !important;
    padding: 0 !important;
    margin: 0 !important;
}
.mes .swipes-counter::before,
.mes .swipe_counter::before {
    display: none !important;
}
